class APMTransaction:
    """Represents a single transaction being monitored."""
    
    def __init__(self, name, transaction_type="request"):
        self.name = name
        self.transaction_type = transaction_type
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.spans = []
        self.context = {}
        self.result = None
        self.outcome = "unknown"
        self.stack_traces = []
        self.labels = {}
    
    def end(self, result=None):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
        if result:
            self.result = result
    
    def set_label(self, key, value):
        self.labels[key] = value
    
    def to_dict(self):
        return {
            "name": self.name,
            "type": self.transaction_type,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "end_time": datetime.fromtimestamp(self.end_time).isoformat() if self.end_time else None,
            "duration_ms": self.duration_ms,
            "result": self.result,
            "outcome": self.outcome,
            "spans_count": len(self.spans),
            "labels": self.labels,
            "context": self.context,
            "spans": [s.to_dict() for s in self.spans],
            "stack_traces": self.stack_traces,
        }


class APMSpan:
    """Represents a span within a transaction (e.g., DB query, HTTP call)."""
    
    def __init__(self, name, span_type="custom", subtype=None, action=None):
        self.name = name
        self.span_type = span_type
        self.subtype = subtype
        self.action = action
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.context = {}
        self.stack_trace = None
    
    def end(self):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
    
    def to_dict(self):
        return {
            "name": self.name,
            "type": self.span_type,
            "subtype": self.subtype,
            "action": self.action,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "duration_ms": self.duration_ms,
            "context": self.context,
            "stack_trace": self.stack_trace,
        }


class APMClient:
    """
    Custom APM Client that captures transactions, spans, errors, and metrics.
    Can work standalone or integrate with Elastic APM.
    """
    
    def __init__(self, config=None):
        self.config = config or {}
        self.service_name = self.config.get("SERVICE_NAME", "python-apm-app")
        self.environment = self.config.get("ENVIRONMENT", "development")
        self.server_url = self.config.get("SERVER_URL", "http://localhost:8200")
        self.capture_body = self.config.get("CAPTURE_BODY", "all")
        self.capture_headers = self.config.get("CAPTURE_HEADERS", True)
        self.collect_db_queries = self.config.get("COLLECT_DB_QUERIES", True)
        self.stack_trace_limit = self.config.get("STACK_TRACE_LIMIT", 50)
        self.transaction_sample_rate = self.config.get("TRANSACTION_SAMPLE_RATE", 1.0)
        
        self.transactions = []
        self.errors = []
        self.metrics = []
        self._current_transaction = None
        self._elastic_client = None
        
        # Try to initialize Elastic APM client
        self._init_elastic_apm()
        
        logger.info(
            f"APM Client initialized - Service: {self.service_name}, "
            f"Environment: {self.environment}, Server: {self.server_url}"
        )
    
    def _init_elastic_apm(self):
        """Try to initialize Elastic APM client if available."""
        try:
            import elasticapm
            self._elastic_client = elasticapm.Client(
                service_name=self.service_name,
                server_url=self.server_url,
                environment=self.environment,
                capture_body=self.capture_body,
                capture_headers=self.capture_headers,
                collect_db_queries=self.collect_db_queries,
                stack_trace_limit=self.stack_trace_limit,
                transaction_sample_rate=self.transaction_sample_rate,
                # Additional configuration for full data capture
                auto_log_stacks=True,
                capture_exception=True,
                metrics_interval="30s",
                central_config=True,
                global_labels={
                    "app_version": "1.0.0",
                    "deployment": self.environment,
                },
            )
            logger.info("Elastic APM client initialized successfully")
        except ImportError:
            logger.warning(
                "elastic-apm not installed. Using custom APM implementation. "
                "Install with: pip install elastic-apm"
            )
        except Exception as e:
            logger.warning(f"Failed to initialize Elastic APM: {e}. Using custom implementation.")
    
    def begin_transaction(self, name, transaction_type="request"):
        """Begin a new transaction."""
        transaction = APMTransaction(name, transaction_type)
        self._current_transaction = transaction
        
        if self._elastic_client:
            try:
                import elasticapm
                elasticapm.instrument()
                self._elastic_client.begin_transaction(transaction_type)
            except Exception as e:
                logger.debug(f"Elastic APM begin_transaction failed: {e}")
        
        logger.debug(f"Transaction started: {name} ({transaction_type})")
        return transaction
    
    def end_transaction(self, name=None, result=None):
        """End the current transaction."""
        if self._current_transaction:
            self._current_transaction.end(result)
            if result and str(result).startswith(("2", "success")):
                self._current_transaction.outcome = "success"
            elif result and str(result).startswith(("4", "5", "error", "failure")):
                self._current_transaction.outcome = "failure"
            else:
                self._current_transaction.outcome = "success"
            
            self.transactions.append(self._current_transaction)
            
            if self._elastic_client:
                try:
                    self._elastic_client.end_transaction(
                        name or self._current_transaction.name, result
                    )
                except Exception as e:
                    logger.debug(f"Elastic APM end_transaction failed: {e}")
            
            logger.info(
                f"Transaction ended: {self._current_transaction.name} - "
                f"Duration: {self._current_transaction.duration_ms:.2f}ms - "
                f"Result: {result} - Outcome: {self._current_transaction.outcome}"
            )
            
            transaction = self._current_transaction
            self._current_transaction = None
            return transaction
        return None
    
    def begin_span(self, name, span_type="custom", subtype=None, action=None):
        """Begin a new span within the current transaction."""
        span = APMSpan(name, span_type, subtype, action)
        
        if self._elastic_client:
            try:
                import elasticapm
                elasticapm.label(**{"span_name": name})
            except Exception:
                pass
        
        logger.debug(f"Span started: {name} ({span_type}.{subtype}.{action})")
        return span
    
    def end_span(self, span):
        """End a span and attach it to the current transaction."""
        if span:
            span.end()
            if self._current_transaction:
                self._current_transaction.spans.append(span)
            
            logger.debug(
                f"Span ended: {span.name} - Duration: {span.duration_ms:.2f}ms"
            )
    
    def capture_exception(self, exc_info=None):
        """Capture an exception with full stack trace."""
        import traceback
        import sys
        
        if exc_info is None:
            exc_info = sys.exc_info()
        
        if exc_info[0] is not None:
            stack_trace = traceback.format_exception(*exc_info)
            error_data = {
                "timestamp": datetime.now().isoformat(),
                "exception_type": exc_info[0].__name__,
                "exception_message": str(exc_info[1]),
                "stack_trace": "".join(stack_trace),
                "transaction": self._current_transaction.name if self._current_transaction else None,
            }
            self.errors.append(error_data)
            
            if self._current_transaction:
                self._current_transaction.stack_traces.append("".join(stack_trace))
                self._current_transaction.outcome = "failure"
            
            if self._elastic_client:
                try:
                    self._elastic_client.capture_exception(exc_info=exc_info)
                except Exception as e:
                    logger.debug(f"Elastic APM capture_exception failed: {e}")
            
            logger.error(
                f"Exception captured: {exc_info[0].__name__}: {exc_info[1]}"
            )
    
    def capture_message(self, message, param_message=None, **kwargs):
        """Capture a custom message."""
        msg_data = {
            "timestamp": datetime.now().isoformat(),
            "message": message,
            "params": param_message,
            "extra": kwargs,
        }
        
        if self._elastic_client:
            try:
                self._elastic_client.capture_message(message, **kwargs)
            except Exception:
                pass
        
        logger.info(f"APM Message: {message}")
        return msg_data
    
    def set_transaction_context(self, context_type, data):
        """Set context data on the current transaction."""
        if self._current_transaction:
            self._current_transaction.context[context_type] = data
    
    def record_metric(self, name, value, unit=None, labels=None):
        """Record a custom metric."""
        metric = {
            "timestamp": datetime.now().isoformat(),
            "name": name,
            "value": value,
            "unit": unit,
            "labels": labels or {},
        }
        self.metrics.append(metric)
        logger.debug(f"Metric recorded: {name}={value} {unit or ''}")
    
    def get_performance_report(self):
        """Generate a performance report from collected data."""
        if not self.transactions:
            return {"message": "No transactions recorded yet"}
        
        durations = [t.duration_ms for t in self.transactions if t.duration_ms]
        
        report = {
            "service_name": self.service_name,
            "environment": self.environment,
            "report_time": datetime.now().isoformat(),
            "summary": {
                "total_transactions": len(self.transactions),
                "total_errors": len(self.errors),
                "total_metrics": len(self.metrics),
                "avg_duration_ms": sum(durations) / len(durations) if durations else 0,
                "min_duration_ms": min(durations) if durations else 0,
                "max_duration_ms": max(durations) if durations else 0,
                "p95_duration_ms": sorted(durations)[int(len(durations) * 0.95)] if durations else 0,
                "success_rate": (
                    sum(1 for t in self.transactions if t.outcome == "success")
                    / len(self.transactions) * 100
                ) if self.transactions else 0,
            },
            "transactions": [t.to_dict() for t in self.transactions[-10:]],  # Last 10
            "errors": self.errors[-10:],  # Last 10 errors
            "metrics": self.metrics[-20:],  # Last 20 metrics
        }
        return report


