def trace_transaction(apm_client, name=None, transaction_type="request"):
    """Decorator to trace a function as an APM transaction."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            tx_name = name or f"{func.__module__}.{func.__qualname__}"
            apm_client.begin_transaction(tx_name, transaction_type)
            
            # Capture request context
            apm_client.set_transaction_context("custom", {
                "function": func.__qualname__,
                "args_count": len(args),
                "kwargs_keys": list(kwargs.keys()),
            })
            
            try:
                result = func(*args, **kwargs)
                apm_client.end_transaction(tx_name, "success")
                return result
            except Exception as e:
                apm_client.capture_exception()
                apm_client.end_transaction(tx_name, "failure")
                raise
        return wrapper
    return decorator


def trace_span(apm_client, name=None, span_type="custom", subtype=None, action=None):
    """Decorator to trace a function as an APM span."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            span_name = name or f"{func.__qualname__}"
            span = apm_client.begin_span(span_name, span_type, subtype, action)
            
            try:
                result = func(*args, **kwargs)
                span.context["result_type"] = type(result).__name__
                apm_client.end_span(span)
                return result
            except Exception as e:
                import traceback
                span.context["error"] = str(e)
                span.stack_trace = traceback.format_exc()
                apm_client.end_span(span)
                raise
        return wrapper
    return decorator


