class InstrumentedDatabase:
    """SQLite database wrapper with full APM instrumentation."""
    
    def __init__(self, apm_client, db_path=":memory:"):
        self.apm_client = apm_client
        self.db_path = db_path
        self.connection = sqlite3.connect(db_path)
        self.connection.row_factory = sqlite3.Row
        logger.info(f"Database connected: {db_path}")
    
    def execute(self, query, params=None, fetch=True):
        """Execute a SQL query with full APM tracking."""
        span = self.apm_client.begin_span(
            name=self._sanitize_query_name(query),
            span_type="db",
            subtype="sqlite",
            action="query"
        )
        
        # Capture full query context
        span.context = {
            "db": {
                "type": "sqlite",
                "instance": self.db_path,
                "statement": query,
                "params": str(params) if params else None,
            }
        }
        
        start = time.time()
        try:
            cursor = self.connection.cursor()
            if params:
                cursor.execute(query, params)
            else:
                cursor.execute(query)
            
            self.connection.commit()
            
            result = None
            if fetch and query.strip().upper().startswith("SELECT"):
                result = [dict(row) for row in cursor.fetchall()]
                span.context["db"]["rows_affected"] = len(result)
            else:
                span.context["db"]["rows_affected"] = cursor.rowcount
                result = cursor.rowcount
            
            duration = (time.time() - start) * 1000
            span.context["db"]["duration_ms"] = duration
            
            # Record query metric
            self.apm_client.record_metric(
                "db.query.duration",
                duration,
                unit="ms",
                labels={"query_type": query.strip().split()[0].upper()}
            )
            
            self.apm_client.end_span(span)
            
            logger.info(
                f"SQL Query executed in {duration:.2f}ms: "
                f"{self._sanitize_query_name(query)}"
            )
            
            return result
            
        except Exception as e:
            span.context["db"]["error"] = str(e)
            import traceback
            span.stack_trace = traceback.format_exc()
            self.apm_client.end_span(span)
            self.apm_client.capture_exception()
            logger.error(f"SQL Error: {e}")
            raise
    
    def _sanitize_query_name(self, query):
        """Create a readable name from a SQL query."""
        query = query.strip()
        parts = query.split()
        if len(parts) >= 2:
            operation = parts[0].upper()
            # Find table name
            if operation in ("SELECT", "DELETE"):
                try:
                    from_idx = [p.upper() for p in parts].index("FROM")
                    table = parts[from_idx + 1]
                except (ValueError, IndexError):
                    table = "unknown"
            elif operation in ("INSERT",):
                try:
                    into_idx = [p.upper() for p in parts].index("INTO")
                    table = parts[into_idx + 1]
                except (ValueError, IndexError):
                    table = "unknown"
            elif operation in ("UPDATE",):
                table = parts[1]
            elif operation in ("CREATE", "DROP"):
                table = parts[2] if len(parts) > 2 else parts[1]
            else:
                table = "unknown"
            return f"{operation} {table}"
        return query[:50]
    
    def close(self):
        self.connection.close()
        logger.info("Database connection closed")


