class InstrumentedHTTPClient:
    """Simulated HTTP client with APM instrumentation."""
    
    def __init__(self, apm_client):
        self.apm_client = apm_client
    
    def request(self, method, url, headers=None, body=None):
        """Make an instrumented HTTP request (simulated)."""
        span = self.apm_client.begin_span(
            name=f"{method} {url}",
            span_type="external",
            subtype="http",
            action=method.lower()
        )
        
        # Capture full request context
        span.context = {
            "http": {
                "method": method,
                "url": url,
                "request_headers": headers or {},
                "request_body": body,
            }
        }
        
        try:
            # Simulate HTTP request
            time.sleep(0.05)  # Simulate network latency
            
            # Simulated response
            response = {
                "status_code": 200,
                "headers": {"Content-Type": "application/json"},
                "body": {"status": "ok", "data": "simulated_response"},
            }
            
            span.context["http"]["status_code"] = response["status_code"]
            span.context["http"]["response_headers"] = response["headers"]
            span.context["http"]["response_body"] = response["body"]
            
            self.apm_client.record_metric(
                "http.client.duration",
                span.duration_ms if span.duration_ms else 50,
                unit="ms",
                labels={"method": method, "url": url}
            )
            
            self.apm_client.end_span(span)
            return response
            
        except Exception as e:
            span.context["http"]["error"] = str(e)
            self.apm_client.end_span(span)
            self.apm_client.capture_exception()
            raise


