def create_flask_app(apm_client):
    """Create a Flask application with APM middleware."""
    try:
        from flask import Flask, request, jsonify, g
        
        app = Flask(__name__)
        
        # Try to use Elastic APM Flask integration
        try:
            from elasticapm.contrib.flask import ElasticAPM
            elastic_apm = ElasticAPM(
                app,
                server_url=apm_client.server_url,
                service_name=apm_client.service_name,
                environment=apm_client.environment,
                capture_body="all",
                capture_headers=True,
                auto_log_stacks=True,
                collect_db_queries=True,
            )
            logger.info("Elastic APM Flask integration enabled")
        except ImportError:
            logger.info("Using custom APM middleware for Flask")
        
        # Custom APM middleware
        @app.before_request
        def before_request():
            g.apm_transaction = apm_client.begin_transaction(
                f"{request.method} {request.path}",
                "request"
            )
            apm_client.set_transaction_context("request", {
                "method": request.method,
                "url": request.url,
                "headers": dict(request.headers),
                "body": request.get_data(as_text=True),
                "query_params": dict(request.args),
                "remote_addr": request.remote_addr,
            })
        
        @app.after_request
        def after_request(response):
            apm_client.set_transaction_context("response", {
                "status_code": response.status_code,
                "headers": dict(response.headers),
                "body_size": response.content_length,
            })
            
            result = str(response.status_code)
            apm_client.end_transaction(
                f"{request.method} {request.path}",
                result
            )
            
            apm_client.record_metric(
                "http.server.duration",
                (time.time() - g.apm_transaction.start_time) * 1000,
                unit="ms",
                labels={
                    "method": request.method,
                    "path": request.path,
                    "status": response.status_code,
                }
            )
            
            return response
        
        @app.errorhandler(Exception)
        def handle_error(error):
            apm_client.capture_exception()
            return jsonify({"error": str(error)}), 500
        
        # Initialize database
        db = InstrumentedDatabase(apm_client)
        db.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                email TEXT UNIQUE NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """, fetch=False)
        
        db.execute("""
            CREATE TABLE IF NOT EXISTS orders (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                product TEXT NOT NULL,
                amount REAL NOT NULL,
                status TEXT DEFAULT 'pending',
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(id)
            )
        """, fetch=False)
        
        # Routes
        @app.route("/")
        def index():
            return jsonify({
                "service": apm_client.service_name,
                "status": "running",
                "endpoints": [
                    "/users", "/users/<id>", "/orders",
                    "/apm/report", "/apm/health", "/error"
                ]
            })
        
        @app.route("/users", methods=["GET", "POST"])
        def users():
            if request.method == "POST":
                data = request.get_json()
                db.execute(
                    "INSERT INTO users (name, email) VALUES (?, ?)",
                    (data["name"], data["email"]),
                    fetch=False
                )
                return jsonify({"status": "created", "user": data}), 201
            else:
                result = db.execute("SELECT * FROM users")
                return jsonify(result)
        
        @app.route("/users/<int:user_id>")
        def get_user(user_id):
            result = db.execute(
                "SELECT * FROM users WHERE id = ?", (user_id,)
            )
            if result:
                return jsonify(result[0])
            return jsonify({"error": "User not found"}), 404
        
        @app.route("/orders", methods=["GET", "POST"])
        def orders():
            if request.method == "POST":
                data = request.get_json()
                db.execute(
                    "INSERT INTO orders (user_id, product, amount) VALUES (?, ?, ?)",
                    (data["user_id"], data["product"], data["amount"]),
                    fetch=False
                )
                
                # Simulate external API call
                http_client = InstrumentedHTTPClient(apm_client)
                http_client.request(
                    "POST",
                    "https://api.payment.example.com/charge",
                    headers={"Authorization": "Bearer xxx"},
                    body={"amount": data["amount"]}
                )
                
                return jsonify({"status": "created", "order": data}), 201
            else:
                result = db.execute("""
                    SELECT o.*, u.name as user_name 
                    FROM orders o 
                    JOIN users u ON o.user_id = u.id
                """)
                return jsonify(result)
        
        @app.route("/apm/report")
        def apm_report():
            return jsonify(apm_client.get_performance_report())
        
        @app.route("/apm/health")
        def apm_health():
            return jsonify({
                "status": "healthy",
                "apm_enabled": True,
                "elastic_apm": apm_client._elastic_client is not None,
                "transactions_captured": len(apm_client.transactions),
                "errors_captured": len(apm_client.errors),
                "metrics_captured": len(apm_client.metrics),
            })
        
        @app.route("/error")
        def trigger_error():
            # Intentionally trigger an error to test APM error capture
            raise ValueError("This is a test error for APM monitoring")
        
        @app.route("/slow")
        def slow_endpoint():
            """Simulate a slow endpoint for performance testing."""
            span = apm_client.begin_span(
                "heavy_computation", "custom", "compute", "process"
            )
            time.sleep(0.5)  # Simulate slow processing
            apm_client.end_span(span)
            
            # Multiple DB queries
            for i in range(5):
                db.execute("SELECT * FROM users")
            
            return jsonify({"status": "completed", "note": "This was intentionally slow"})
        
        return app, db
        
    except ImportError:
        logger.warning("Flask not available. Run: pip install flask")
        return None, None


