class SampleApplication:
    """Sample application demonstrating APM instrumentation."""
    
    def __init__(self):
        self.apm = APMClient({
            "SERVICE_NAME": "sample-python-app",
            "ENVIRONMENT": os.getenv("APP_ENV", "development"),
            "SERVER_URL": os.getenv("APM_SERVER_URL", "http://localhost:8200"),
            "CAPTURE_BODY": "all",
            "CAPTURE_HEADERS": True,
            "COLLECT_DB_QUERIES": True,
            "STACK_TRACE_LIMIT": 50,
            "TRANSACTION_SAMPLE_RATE": 1.0,
        })
        self.db = InstrumentedDatabase(self.apm)
        self.http_client = InstrumentedHTTPClient(self.apm)
        self._setup_database()
    
    def _setup_database(self):
        """Set up the database schema."""
        self.db.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                email TEXT UNIQUE NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """, fetch=False)
        
        self.db.execute("""
            CREATE TABLE IF NOT EXISTS products (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                price REAL NOT NULL,
                stock INTEGER DEFAULT 0
            )
        """, fetch=False)
        
        self.db.execute("""
            CREATE TABLE IF NOT EXISTS orders (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                product_id INTEGER NOT NULL,
                quantity INTEGER NOT NULL,
                total REAL NOT NULL,
                status TEXT DEFAULT 'pending',
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(id),
                FOREIGN KEY (product_id) REFERENCES products(id)
            )
        """, fetch=False)
        
        logger.info("Database schema created successfully")
    
    @trace_transaction(None, "create_user", "custom")
    def create_user(self, name, email):
        """Create a new user with full APM tracking."""
        # This decorator won't work directly since apm_client is None at class definition
        # We'll use manual instrumentation instead
        pass
    
    def create_user_instrumented(self, name, email):
        """Create a new user with manual APM instrumentation."""
        self.apm.begin_transaction("create_user", "custom")
        self.apm.set_transaction_context("request", {
            "operation": "create_user",
            "params": {"name": name, "email": email},
        })
        
        try:
            self.db.execute(
                "INSERT INTO users (name, email) VALUES (?, ?)",
                (name, email),
                fetch=False
            )
            
            users = self.db.execute(
                "SELECT * FROM users WHERE email = ?", (email,)
            )
            
            self.apm.set_transaction_context("response", {
                "user": users[0] if users else None,
            })
            
            self.apm.end_transaction("create_user", "success")
            return users[0] if users else None
            
        except Exception as e:
            self.apm.capture_exception()
            self.apm.end_transaction("create_user", "failure")
            raise
    
    def create_product(self, name, price, stock):
        """Create a new product."""
        self.apm.begin_transaction("create_product", "custom")
        
        try:
            self.db.execute(
                "INSERT INTO products (name, price, stock) VALUES (?, ?, ?)",
                (name, price, stock),
                fetch=False
            )
            
            products = self.db.execute(
                "SELECT * FROM products WHERE name = ?", (name,)
            )
            
            self.apm.end_transaction("create_product", "success")
            return products[0] if products else None
            
        except Exception as e:
            self.apm.capture_exception()
            self.apm.end_transaction("create_product", "failure")
            raise
    
    def place_order(self, user_id, product_id, quantity):
        """Place an order with full transaction tracking."""
        self.apm.begin_transaction("place_order", "custom")
        self.apm.set_transaction_context("request", {
            "user_id": user_id,
            "product_id": product_id,
            "quantity": quantity,
        })
        
        try:
            # Check user exists
            span = self.apm.begin_span("validate_user", "custom", "validation")
            users = self.db.execute(
                "SELECT * FROM users WHERE id = ?", (user_id,)
            )
            if not users:
                raise ValueError(f"User {user_id} not found")
            self.apm.end_span(span)
            
            # Check product exists and has stock
            span = self.apm.begin_span("validate_product", "custom", "validation")
            products = self.db.execute(
                "SELECT * FROM products WHERE id = ?", (product_id,)
            )
            if not products:
                raise ValueError(f"Product {product_id} not found")
            product = products[0]
            if product["stock"] < quantity:
                raise ValueError(
                    f"Insufficient stock. Available: {product['stock']}, Requested: {quantity}"
                )
            self.apm.end_span(span)
            
            # Calculate total
            total = product["price"] * quantity
            
            # Process payment (simulated external call)
            span = self.apm.begin_span("process_payment", "external", "http", "post")
            payment_response = self.http_client.request(
                "POST",
                "https://api.payment.example.com/charge",
                headers={"Authorization": "Bearer token123"},
                body={"amount": total, "user_id": user_id}
            )
            self.apm.end_span(span)
            
            # Create order
            self.db.execute(
                "INSERT INTO orders (user_id, product_id, quantity, total, status) VALUES (?, ?, ?, ?, ?)",
                (user_id, product_id, quantity, total, "confirmed"),
                fetch=False
            )
            
            # Update stock
            self.db.execute(
                "UPDATE products SET stock = stock - ? WHERE id = ?",
                (quantity, product_id),
                fetch=False
            )
            
            # Record business metrics
            self.apm.record_metric("order.total", total, "USD", {"product": product["name"]})
            self.apm.record_metric("order.quantity", quantity, "items")
            
            self.apm.set_transaction_context("response", {
                "order_total": total,
                "payment_status": payment_response["status_code"],
            })
            
            self.apm.end_transaction("place_order", "success")
            
            return {
                "status": "confirmed",
                "total": total,
                "user": users[0]["name"],
                "product": product["name"],
                "quantity": quantity,
            }
            
        except Exception as e:
            self.apm.capture_exception()
            self.apm.end_transaction("place_order", "failure")
            raise
    
    def get_order_report(self):
        """Generate an order report with APM tracking."""
        self.apm.begin_transaction("get_order_report", "custom")
        
        try:
            orders = self.db.execute("""
                SELECT o.*, u.name as user_name, p.name as product_name
                FROM orders o
                JOIN users u ON o.user_id = u.id
                JOIN products p ON o.product_id = p.id
                ORDER BY o.created_at DESC
            """)
            
            total_revenue = self.db.execute(
                "SELECT COALESCE(SUM(total), 0) as revenue FROM orders WHERE status = 'confirmed'"
            )
            
            report = {
                "orders": orders,
                "total_revenue": total_revenue[0]["revenue"] if total_revenue else 0,
                "order_count": len(orders),
            }
            
            self.apm.end_transaction("get_order_report", "success")
            return report
            
        except Exception as e:
            self.apm.capture_exception()
            self.apm.end_transaction("get_order_report", "failure")
            raise
    
    def simulate_error(self):
        """Simulate an error to test APM error capture."""
        self.apm.begin_transaction("simulate_error", "custom")
        
        try:
            # This will cause an error
            result = 1 / 0
        except Exception:
            self.apm.capture_exception()
            self.apm.end_transaction("simulate_error", "failure")
    
    def run_demo(self):
        """Run a full demonstration of the APM-instrumented application."""
        logger.info("=" * 60)
        logger.info("Starting APM Demo Application")
        logger.info("=" * 60)
        
        # 1. Create users
        logger.info("\n--- Creating Users ---")
        user1 = self.create_user_instrumented("Alice Johnson", "alice@example.com")
        user2 = self.create_user_instrumented("Bob Smith", "bob@example.com")
        user3 = self.create_user_instrumented("Charlie Brown", "charlie@example.com")
        logger.info(f"Created users: {user1}, {user2}, {user3}")
        
        # 2. Create products
        logger.info("\n--- Creating Products ---")
        prod1 = self.create_product("Laptop", 999.99, 50)
        prod2 = self.create_product("Headphones", 149.99, 200)
        prod3 = self.create_product("Keyboard", 79.99, 150)
        logger.info(f"Created products: {prod1}, {prod2}, {prod3}")
        
        # 3. Place orders
        logger.info("\n--- Placing Orders ---")
        order1 = self.place_order(1, 1, 2)  # Alice buys 2 laptops
        logger.info(f"Order 1: {order1}")
        
        order2 = self.place_order(2, 2, 3)  # Bob buys 3 headphones
        logger.info(f"Order 2: {order2}")
        
        order3 = self.place_order(3, 3, 5)  # Charlie buys 5 keyboards
        logger.info(f"Order 3: {order3}")
        
        order4 = self.place_order(1, 2, 1)  # Alice buys 1 headphone
        logger.info(f"Order 4: {order4}")
        
        # 4. Get order report
        logger.info("\n--- Order Report ---")
        report = self.get_order_report()
        logger.info(f"Total orders: {report['order_count']}")
        logger.info(f"Total revenue: ${report['total_revenue']:.2f}")
        
        # 5. Simulate an error
        logger.info("\n--- Simulating Error ---")
        self.simulate_error()
        
        # 6. Try placing an order with invalid data
        logger.info("\n--- Testing Error Handling ---")
        try:
            self.place_order(999, 1, 1)  # Non-existent user
        except ValueError as e:
            logger.info(f"Expected error caught: {e}")
        
        # 7. Print APM Performance Report
        logger.info("\n" + "=" * 60)
        logger.info("APM PERFORMANCE REPORT")
        logger.info("=" * 60)
        
        perf_report = self.apm.get_performance_report()
        print(json.dumps(perf_report, indent=2, default=str))
        
        # Cleanup
        self.db.close()
        
        return perf_report


# ============================================================
# Main entry point
# ============================================================

def main():
    """Main entry point - runs either Flask app or standalone demo."""
    
    mode = os.getenv("APP_MODE", "demo")  # "demo", "flask", or "both"
    
    if mode in ("flask", "both"):
        # Initialize APM client for Flask
        apm_config = {
            "SERVICE_NAME": os.getenv("APM_SERVICE_NAME", "flask-apm-app"),
            "ENVIRONMENT": os.getenv("APP_ENV", "development"),
            "SERVER_URL": os.getenv("APM_SERVER_URL", "http://localhost:8200"),
            "CAPTURE_BODY": "all",
            "CAPTURE_HEADERS": True,
            "COLLECT_DB_QUERIES": True,
            "STACK_TRACE_LIMIT": 50,
            "TRANSACTION_SAMPLE_RATE": 1.0,
        }
        apm_client = APMClient(apm_config)
        
        app, db = create_flask_app(apm_client)
        
        if app:
            host = os.getenv("FLASK_HOST", "0.0.0.0")
            port = int(os.getenv("FLASK_PORT", "5000"))
            debug = os.getenv("FLASK_DEBUG", "true").lower() == "true"
            
            logger.info(f"Starting Flask app on {host}:{port}")
            logger.info(f"APM Dashboard: http://{host}:{port}/apm/report")
            logger.info(f"Health Check: http://{host}:{port}/apm/health")
            
            if mode == "both":
                # Run demo first, then start Flask
                demo_app = SampleApplication()
                demo_app.run_demo()
            
            app.run(host=host, port=port, debug=debug)
        else:
            logger.info("Flask not available, falling back to demo mode")
            mode = "demo"
    
    if mode == "demo":
        # Run standalone demo
        app = SampleApplication()
        report = app.run_demo()
        
        # Save report to file
        report_path = "apm_report.json"
        with open(report_path, "w") as f:
            json.dump(report, f, indent=2, default=str)
        logger.info(f"\nAPM report saved to {report_path}")


if __name__ == "__main__":
    main()